import java.util.Arrays;
public class SortColors {
    public static void sortColors(int[] nums) {
        int low = 0, mid = 0, high = nums.length - 1;
        while (mid <= high) {
            if (nums[mid] == 0) {
                // Swap with low, advance both
                int tmp = nums[low]; nums[low] = nums[mid]; nums[mid] = tmp;
                low++; mid++;
            } else if (nums[mid] == 1) {
                mid++; // already in correct region
            } else {
                // Swap with high, advance high only — re-examine mid
                int tmp = nums[mid]; nums[mid] = nums[high]; nums[high] = tmp;
                high--;
            }
        }
    }
    public static void main(String[] args) {
        int[] a = {2,0,2,1,1,0}; sortColors(a);
        System.out.println(Arrays.toString(a)); // [0,0,1,1,2,2]
        int[] b = {2,0,1}; sortColors(b);
        System.out.println(Arrays.toString(b)); // [0,1,2]
        int[] c = {0}; sortColors(c);
        System.out.println(Arrays.toString(c)); // [0]
        System.out.println("O(n) time, O(1) space — one pass DNF");
    }
}

