import java.util.Arrays;
public class PivotPartition {
    public static void partition(int[] arr, int pivot) {
        int low = 0, mid = 0, high = arr.length - 1;
        while (mid <= high) {
            if (arr[mid] < pivot) {
                int tmp = arr[low]; arr[low] = arr[mid]; arr[mid] = tmp;
                low++; mid++;
            } else if (arr[mid] == pivot) {
                mid++;
            } else { // arr[mid] > pivot
                int tmp = arr[mid]; arr[mid] = arr[high]; arr[high] = tmp;
                high--;
            }
        }
    }
    static boolean verify(int[] arr, int pivot) {
        int i = 0;
        while (i < arr.length && arr[i] < pivot) i++;
        while (i < arr.length && arr[i] == pivot) i++;
        while (i < arr.length && arr[i] > pivot) i++;
        return i == arr.length;
    }
    public static void main(String[] args) {
        int[] a = {3,5,1,5,2,5,4};
        partition(a, 5);
        System.out.println(Arrays.toString(a));
        System.out.println("Valid partition: " + verify(a, 5));
        System.out.println("O(n) time, O(1) space — DNF generalized to any pivot value");
    }
}

