import java.util.Arrays;
public class OrderStatusSort {
    static int val(String s) {
        return switch (s) { case "PENDING" -> 0; case "EXECUTED" -> 1; default -> 2; };
    }
    public static void sortOrders(String[] orders) {
        int low = 0, mid = 0, high = orders.length - 1;
        while (mid <= high) {
            int v = val(orders[mid]);
            if (v == 0) {
                String tmp = orders[low]; orders[low] = orders[mid]; orders[mid] = tmp;
                low++; mid++;
            } else if (v == 1) {
                mid++;
            } else {
                String tmp = orders[mid]; orders[mid] = orders[high]; orders[high] = tmp;
                high--;
            }
        }
    }
    public static void main(String[] args) {
        String[] orders = {"FAILED","PENDING","EXECUTED","PENDING","FAILED","EXECUTED"};
        sortOrders(orders);
        System.out.println(Arrays.toString(orders));
        // Verify structure:
        int i = 0;
        while (i < orders.length && orders[i].equals("PENDING")) i++;
        while (i < orders.length && orders[i].equals("EXECUTED")) i++;
        while (i < orders.length && orders[i].equals("FAILED")) i++;
        System.out.println("Correctly sorted: " + (i == orders.length));
    }
}

