import java.util.Arrays;
public class SegregateZerosOnes {
    // Approach 1: count then fill O(n) O(1)
    static void countFill(int[] arr) {
        int zeros = 0;
        for (int x : arr) if (x == 0) zeros++;
        for (int i = 0; i < zeros; i++) arr[i] = 0;
        for (int i = zeros; i < arr.length; i++) arr[i] = 1;
    }
    // Approach 2: two-pointer swap (in-place, preserves relative order for 0s)
    static void twoPointer(int[] arr) {
        int lo = 0, hi = arr.length - 1;
        while (lo < hi) {
            while (lo < hi && arr[lo] == 0) lo++; // find 1 from left
            while (lo < hi && arr[hi] == 1) hi--; // find 0 from right
            if (lo < hi) {
                int tmp = arr[lo]; arr[lo] = arr[hi]; arr[hi] = tmp;
                lo++; hi--;
            }
        }
    }
    public static void main(String[] args) {
        int[] a = {1,0,1,0,0,1,1,0};
        int[] b = a.clone();
        countFill(a); twoPointer(b);
        System.out.println("countFill:   " + Arrays.toString(a));
        System.out.println("twoPointer:  " + Arrays.toString(b));
        System.out.println("Same result: " + Arrays.equals(a, b));
        System.out.println("Both O(n) time, O(1) space");
    }
}

