import java.util.Arrays;
public class ThreeWayQuicksort {
    public static void sort(int[] arr, int lo, int hi) {
        if (lo >= hi) return;
        // 3-way partition with arr[lo] as pivot:
        int pivot = arr[lo];
        int lt = lo, gt = hi, i = lo + 1;
        while (i <= gt) {
            if (arr[i] < pivot) {
                int tmp = arr[lt]; arr[lt] = arr[i]; arr[i] = tmp;
                lt++; i++;
            } else if (arr[i] > pivot) {
                int tmp = arr[i]; arr[i] = arr[gt]; arr[gt] = tmp;
                gt--;
                // don't increment i — re-examine
            } else {
                i++; // equal to pivot — in correct place
            }
        }
        // arr[lo..lt-1] < pivot, arr[lt..gt] == pivot, arr[gt+1..hi] > pivot
        sort(arr, lo, lt - 1);   // recurse only on != regions
        sort(arr, gt + 1, hi);
    }
    public static void main(String[] args) {
        int[] a = {4,9,4,4,1,9,4,4,9,4,1,4};
        sort(a, 0, a.length-1);
        System.out.println(Arrays.toString(a)); // [1,1,4,4,4,4,4,4,4,9,9,9]
        System.out.println("Correct: " + isSorted(a));
        System.out.println("3-way partition: duplicates skip recursion → O(n) when all same");
    }
    static boolean isSorted(int[] a) {
        for (int i=0;i<a.length-1;i++) if(a[i]>a[i+1]) return false; return true;
    }
}

