import java.util.*;
public class WiggleSort {
    public static void wiggleSort(int[] nums) {
        // Sort, then interleave: small half in even positions, large half in odd
        int n = nums.length;
        int[] sorted = nums.clone();
        Arrays.sort(sorted);
        // Fill odd positions (1,3,5...) with larger half from right:
        int hi = n - 1, lo = (n - 1) / 2;
        for (int i = 1; i < n; i += 2) nums[i] = sorted[hi--];
        // Fill even positions (0,2,4...) with smaller half from right:
        for (int i = 0; i < n; i += 2) nums[i] = sorted[lo--];
    }
    static boolean isWiggle(int[] nums) {
        for (int i = 1; i < nums.length; i++) {
            if (i % 2 == 1 && nums[i] <= nums[i-1]) return false;
            if (i % 2 == 0 && nums[i] >= nums[i-1]) return false;
        }
        return true;
    }
    public static void main(String[] args) {
        int[] a = {1,5,1,1,6,4}; wiggleSort(a);
        System.out.println(Arrays.toString(a) + " wiggle=" + isWiggle(a));
        int[] b = {1,3,2,2,3,1}; wiggleSort(b);
        System.out.println(Arrays.toString(b) + " wiggle=" + isWiggle(b));
        System.out.println("O(n log n) sort + O(n) interleave — wiggle valid for both tests");
    }
}

