import java.util.*;
public class MoveNegatives {
    // O(n) time, O(n) space — preserves relative order
    static int[] stableSort(int[] arr) {
        int[] result = new int[arr.length];
        int idx = 0;
        for (int x : arr) if (x < 0) result[idx++] = x;  // negatives first
        for (int x : arr) if (x >= 0) result[idx++] = x; // then positives
        return result;
    }
    // O(n) time, O(1) space — two pointers, loses relative order
    static void unstableSort(int[] arr) {
        int lo = 0, hi = arr.length - 1;
        while (lo < hi) {
            while (lo < hi && arr[lo] < 0) lo++;   // find first non-negative
            while (lo < hi && arr[hi] >= 0) hi--;  // find last negative
            if (lo < hi) {
                int tmp = arr[lo]; arr[lo] = arr[hi]; arr[hi] = tmp;
                lo++; hi--;
            }
        }
    }
    public static void main(String[] args) {
        int[] arr = {3,-2,1,-5,4,-1,6};
        System.out.println("Stable:   " + Arrays.toString(stableSort(arr)));
        unstableSort(arr.clone());
        int[] u = arr.clone(); unstableSort(u);
        System.out.println("Unstable: " + Arrays.toString(u));
        System.out.println("Both have same count of negatives/positives");
        System.out.println("Trade-off: stable=O(n) space, unstable=O(1) space");
    }
}

