public class FindDuplicate {
    // Floyd's cycle detection: treat nums[i] as pointer to index nums[i]
    // Duplicate value = entry point of cycle
    public static int findDuplicate(int[] nums) {
        // Phase 1: find meeting point in cycle
        int slow = nums[0], fast = nums[0];
        do {
            slow = nums[slow];
            fast = nums[nums[fast]];
        } while (slow != fast);
        // Phase 2: find cycle entry (= duplicate)
        slow = nums[0];
        while (slow != fast) {
            slow = nums[slow];
            fast = nums[fast];
        }
        return slow; // the duplicate
    }
    public static void main(String[] args) {
        System.out.println(findDuplicate(new int[]{1,3,4,2,2})); // 2
        System.out.println(findDuplicate(new int[]{3,1,3,4,2})); // 3
        System.out.println("O(n) time, O(1) space — Floyd's cycle detection");
        System.out.println("Treat nums[i] as 'next pointer': index i → nums[i]");
    }
}

