import java.util.Arrays;
public class SortParityII {
    public static int[] sortArrayByParityII(int[] nums) {
        int j = 1; // pointer for odd indices needing an even number
        for (int i = 0; i < nums.length; i += 2) {
            if (nums[i] % 2 != 0) { // even index has odd number — wrong
                // find next odd index with even number:
                while (nums[j] % 2 != 0) j += 2;
                // swap:
                int tmp = nums[i]; nums[i] = nums[j]; nums[j] = tmp;
            }
        }
        return nums;
    }
    static boolean verify(int[] nums) {
        for (int i = 0; i < nums.length; i++)
            if (nums[i] % 2 != i % 2) return false;
