public class MinSwapsGroup {
    // Key insight: count of zeros = size of left partition after sorting.
    // Count how many 1s are in the left 'zeros' positions — those need swapping.
    public static int minSwaps(int[] arr) {
        int zeros = 0;
        for (int x : arr) if (x == 0) zeros++;
        // Count 1s in the first 'zeros' positions (the target left region):
        int onesInLeftRegion = 0;
        for (int i = 0; i < zeros; i++) if (arr[i] == 1) onesInLeftRegion++;
        // Each 1 in left region must swap with a 0 in right region:
        return onesInLeftRegion;
    }
    public static void main(String[] args) {
        System.out.println(minSwaps(new int[]{1,0,0,1,0})); // 2
        System.out.println(minSwaps(new int[]{0,0,1,1,1})); // 0
        System.out.println(minSwaps(new int[]{1,1,0,0,0})); // 3
        System.out.println("O(n) time, O(1) space");
        System.out.println("Insight: #swaps = #1s in the first 'zeros' positions");
        System.out.println("Each misplaced 1 pairs with a misplaced 0 for one swap");
    }
}

