import java.util.*;
public class DNFSynthesis {
    static void swap(int[] a, int i, int j){int t=a[i];a[i]=a[j];a[j]=t;}

    static void sortColors(int[] nums) {
        int low=0,mid=0,high=nums.length-1;
        while(mid<=high){if(nums[mid]==0){swap(nums,low++,mid++);}else if(nums[mid]==1){mid++;}else{swap(nums,mid,high--);}}
    }

    static void partitionPivot(int[] arr, int pivot) {
        int low=0,mid=0,high=arr.length-1;
        while(mid<=high){if(arr[mid]<pivot){swap(arr,low++,mid++);}else if(arr[mid]==pivot){mid++;}else{swap(arr,mid,high--);}}
    }

    static void threeWaySort(int[] arr, int lo, int hi) {
        if(lo>=hi) return;
        int pivot=arr[lo],lt=lo,gt=hi,i=lo+1;
        while(i<=gt){if(arr[i]<pivot){swap(arr,lt++,i++);}else if(arr[i]>pivot){swap(arr,i,gt--);}else{i++;}}
        threeWaySort(arr,lo,lt-1); threeWaySort(arr,gt+1,hi);
    }

    static int findDuplicate(int[] nums) {
        int slow=nums[0],fast=nums[0];
        do{slow=nums[slow];fast=nums[nums[fast]];}while(slow!=fast);
        slow=nums[0];
        while(slow!=fast){slow=nums[slow];fast=nums[fast];}
        return slow;
    }

    public static void main(String[] args) {
        int[] a={2,0,2,1,1,0}; sortColors(a);
        System.out.println("1. sortColors: "+Arrays.toString(a));

        int[] b={3,5,1,5,2,5,4}; partitionPivot(b,5);
        boolean pOk=true; int pi=0;
        while(pi<b.length&&b[pi]<5)pi++; while(pi<b.length&&b[pi]==5)pi++;
        while(pi<b.length&&b[pi]>5)pi++; pOk=(pi==b.length);
        System.out.println("2. partitionPivot valid: "+pOk);

        int[] c={4,9,4,4,1,9,4}; threeWaySort(c,0,c.length-1);
        boolean sorted=true; for(int i=0;i<c.length-1;i++) if(c[i]>c[i+1]) sorted=false;
        System.out.println("3. threeWaySort sorted: "+sorted);

        System.out.println("4. findDuplicate: "+findDuplicate(new int[]{1,3,4,2,2}));

        boolean allPass = Arrays.equals(a,new int[]{0,0,1,1,2,2}) && pOk && sorted && findDuplicate(new int[]{1,3,4,2,2})==2;
        System.out.println("All pass: "+allPass);
    }
}
